// ❌ BAD - no hint, skewed data causes the cached plan to crush large customers
CREATE PROCEDURE usp_GetCustomerOrders @CustomerId INT
AS
    SELECT OrderId, Total, OrderDate
    FROM Orders
    WHERE CustomerId = @CustomerId;

// ✅ GOOD - RECOMPILE forces an optimal plan per call; use OPTIMIZE FOR on high-frequency paths
CREATE PROCEDURE usp_GetCustomerOrders @CustomerId INT
AS
    SELECT OrderId, Total, OrderDate
    FROM Orders
    WHERE CustomerId = @CustomerId
    OPTION (RECOMPILE);

-- For high-frequency OLTP: force a known good plan via Query Store
EXEC sp_query_store_force_plan @query_id = 42, @plan_id = 7;

// ❌ BAD - rowstore index on a 200M-row sales fact table; aggregation does a full row-mode scan
CREATE NONCLUSTERED INDEX IX_SalesFact_Date ON SalesFact (SaleDate);
SELECT Region, SUM(Revenue) FROM SalesFact WHERE SaleDate >= '2024-01-01' GROUP BY Region;

// ✅ GOOD - clustered columnstore; same query uses batch-mode and compressed segments
CREATE CLUSTERED COLUMNSTORE INDEX CCI_SalesFact ON SalesFact;
SELECT Region, SUM(Revenue) FROM SalesFact WHERE SaleDate >= '2024-01-01' GROUP BY Region;

-- HTAP: add nonclustered columnstore to live OLTP orders table
CREATE NONCLUSTERED COLUMNSTORE INDEX NCCI_Orders
    ON Orders (OrderDate, CustomerId, Total, Region);

// ❌ BAD - no locking strategy; two sessions read the same balance and both write, one update is silently lost
SELECT Balance FROM Accounts WHERE AccountId = 7;
-- long user think time, another session also decrements
UPDATE Accounts SET Balance = Balance - 200 WHERE AccountId = 7;

// ✅ GOOD - optimistic: rowversion check detects conflict before update is lost
SELECT Balance, RowVer FROM Accounts WHERE AccountId = 7;
UPDATE Accounts
SET Balance = Balance - 200
WHERE AccountId = 7 AND RowVer = @originalRowVer;
-- if @@ROWCOUNT = 0 then conflict - re-read and retry or return 409

-- Pessimistic: lock the row for the duration of the transaction
BEGIN TRANSACTION;
SELECT Balance FROM Accounts WITH (UPDLOCK, HOLDLOCK) WHERE AccountId = 7;
UPDATE Accounts SET Balance = Balance - 200 WHERE AccountId = 7;
COMMIT;

// ❌ BAD - default READ COMMITTED with shared locks; a long-running report blocks all writers on Orders
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;
SELECT SUM(Total) FROM Orders WHERE OrderDate >= '2024-01-01';
-- writers are blocked while this scan holds shared locks row by row

// ✅ GOOD - enable RCSI at database level; same query reads row versions with zero blocking
ALTER DATABASE SalesDb
    SET READ_COMMITTED_SNAPSHOT ON WITH ROLLBACK IMMEDIATE;

-- Same query now runs under READ COMMITTED with versioning - no code change needed
SELECT SUM(Total) FROM Orders WHERE OrderDate >= '2024-01-01';

-- Monitor version store size in tempdb
SELECT reserved_page_count, reserved_space_kb
FROM sys.dm_db_file_space_usage;
